mapper.select:
SELECT u.id AS studentId, u.real_name AS realName, u.org_name AS orgName, u.job_type AS jobType, IFNULL(ec.cnt, 0) AS enrollCount, ROUND(IFNULL(sd.totalSeconds, 0) / 3600.0, 2) AS totalStudyHours, IFNULL(sd.completed, 0) AS completedChapters, ROUND( CASE WHEN IFNULL(tc.totalChapters, 0) = 0 THEN 0 ELSE IFNULL(sd.completed, 0) * 100.0 / tc.totalChapters END, 2 ) AS completionRate, IFNULL(es.avgScore, 0) AS examAvgScore FROM sys_user u -- 报名数 LEFT JOIN ( SELECT student_id, COUNT(*) AS cnt FROM course_enroll WHERE deleted = 0 GROUP BY student_id ) ec ON ec.student_id = u.id -- 学习时长 + 已完成章节数 LEFT JOIN ( SELECT student_id, SUM(study_duration) AS totalSeconds, SUM(CASE WHEN completed = 1 THEN 1 ELSE 0 END) AS completed FROM study_record WHERE deleted = 0 GROUP BY student_id ) sd ON sd.student_id = u.id -- 已报名课程的总章节数 LEFT JOIN ( SELECT ce.student_id, COUNT(ch.id) AS totalChapters FROM course_enroll ce JOIN course_chapter ch ON ch.course_id = ce.course_id AND ch.deleted = 0 WHERE ce.deleted = 0 GROUP BY ce.student_id ) tc ON tc.student_id = u.id -- 考试平均分（仅已批阅） LEFT JOIN ( SELECT student_id, AVG(score) AS avgScore FROM exam_record WHERE deleted = 0 AND status = 2 GROUP BY student_id ) es ON es.student_id = u.id WHERE u.role_id = 3 AND u.deleted = 0
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND u.org_name = #{orgName}
ORDER BY totalStudyHours DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM sys_user u WHERE u.role_id = 3 AND u.deleted = 0
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
AND u.org_name = #{orgName}

SELECT e.id AS examId, e.title AS examTitle, e.pass_score AS passScore, COUNT(er.id) AS participantCount, IFNULL(AVG(er.score), 0) AS avgScore, IFNULL(MAX(er.score), 0) AS maxScore, IFNULL(MIN(er.score), 0) AS minScore, ROUND( CASE WHEN COUNT(er.id) = 0 THEN 0 ELSE SUM(CASE WHEN er.score >= e.pass_score THEN 1 ELSE 0 END) * 100.0 / COUNT(er.id) END, 2 ) AS passRate FROM exam e LEFT JOIN exam_record er ON er.exam_id = e.id AND er.deleted = 0 AND er.status = 2 WHERE e.deleted = 0
AND e.id = #{examId}
GROUP BY e.id, e.title, e.pass_score ORDER BY e.id

SELECT CASE WHEN er.score < 60 THEN '0-59' WHEN er.score < 70 THEN '60-69' WHEN er.score < 80 THEN '70-79' WHEN er.score < 90 THEN '80-89' ELSE '90-100' END AS `range`, COUNT(*) AS `count` FROM exam_record er JOIN exam e ON e.id = er.exam_id WHERE er.deleted = 0 AND er.status = 2
AND er.exam_id = #{examId}
GROUP BY `range` ORDER BY `range`

SELECT c.id AS courseId, c.title AS title, t.real_name AS teacherName, IFNULL(ec.cnt, 0) AS enrollCount, IFNULL(sc.cnt, 0) AS studyCount, IFNULL(sc.avgProgress, 0) AS avgProgress, IFNULL(sc.completionRate, 0) AS completionRate FROM course c LEFT JOIN teacher t ON t.id = c.teacher_id AND t.deleted = 0 LEFT JOIN ( SELECT course_id, COUNT(*) AS cnt FROM course_enroll WHERE deleted = 0 GROUP BY course_id ) ec ON ec.course_id = c.id LEFT JOIN ( SELECT course_id, COUNT(DISTINCT student_id) AS cnt, AVG(progress) AS avgProgress, ROUND(AVG(CASE WHEN progress >= 100 THEN 100 ELSE 0 END), 2) AS completionRate FROM study_record WHERE deleted = 0 GROUP BY course_id ) sc ON sc.course_id = c.id WHERE c.deleted = 0
AND c.title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY enrollCount DESC LIMIT #{size} OFFSET #{offset}
